sys_script.script:
// Check if this is a claims submission
var catItem = current.cat_item.toString();
if (catItem && current.cat_item.name && current.cat_item.name.toString().indexOf('Insurance Claim Submission') > -1) {

    // Get catalog item variables
    var variables = {};
    var variableGR = new GlideRecord('sc_item_option_mtom');
    variableGR.addQuery('request_item', current.getUniqueValue());
    variableGR.query();

    while (variableGR.next()) {
        var varName = variableGR.sc_item_option.name.toString();
        var varValue = variableGR.getValue('value');
        variables[varName] = varValue;
    }

    // Find the client by policy number
    var clientRef = '';
    if (variables.policy_number) {
        var policyGR = new GlideRecord('x_1945663_insuranc_u_insurance_clients_data');
        policyGR.addQuery('policy_number', variables.policy_number);
        policyGR.query();

        if (policyGR.next()) {
            clientRef = policyGR.getUniqueValue();
        }
    }

    if (clientRef) {
        // Create new claims record
        var claimsGR = new GlideRecord('x_1945663_insuranc_u_claims_data');
        claimsGR.initialize();

        claimsGR.setValue('client_reference', clientRef);

        // Generate claim number
        var claimNumber = 'CLM-' + new GlideDateTime().getNumericValue();
        claimsGR.setValue('claim_number', claimNumber);

        claimsGR.setValue('incident_date', variables.accident_date || new GlideDateTime().getDisplayValue());
        claimsGR.setValue('reported_date', new GlideDateTime().getDisplayValue());
        claimsGR.setValue('claim_amount', variables.claim_amount || 0);
        claimsGR.setValue('description', variables.accident_description || '');
        claimsGR.setValue('claim_status', 'submitted');

        var newClaimId = claimsGR.insert();

        if (newClaimId) {
            // Update the catalog request
            current.setValue('state', '3'); // Closed Complete
            current.setValue('stage', 'closed_complete');
            var workNotes = 'Claim submitted successfully. Claim Number: ' + claimNumber + 
                          '\nClaim ID: ' + newClaimId;
            current.setWorkNotes(workNotes);

            // Fire claim notification event
            gs.eventQueue('insurance.claim.status.update', claimsGR,
                         policyGR.getValue('client_name'),
                         claimNumber,
                         'submitted',
                         variables.email);

            gs.info('New claim created from catalog submission: ' + claimNumber);
        }
    } else {
        gs.addErrorMessage('Policy number not found: ' + variables.policy_number);
    }
}
